<?phpnamespace App\Models;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;class Movie extends Model{    use HasFactory;    protected $fillable = [        'id',        'title',        'year',        'rating',        'genre',        'cover_id',        'backdrop_id',        'collection_type',        'runtime',        'rating_age',        'overview',        'director',        'trailer_url',        'boxset_parent',        'user_id',        'is_deleted',        'view_count',        'tmdb_id',        'tmdb_type',        'tmdb_json',        'created_at',        'updated_at',    ];    protected $casts = [        'is_deleted' => 'boolean',        'year' => 'integer',        'runtime' => 'integer',        'view_count' => 'integer',        'tmdb_json' => 'array',    ];    public function user()    {        return $this->belongsTo(User::class);    }    public function parentBoxset()    {        return $this->belongsTo(Movie::class, 'boxset_parent');    }    public function boxsetChildren()    {        return $this->hasMany(Movie::class, 'boxset_parent');    }    public function actors()    {        return $this->belongsToMany(Actor::class, 'film_actor', 'film_id', 'actor_id')                    ->withPivot(['role', 'is_main_role', 'sort_order']);    }    public function seasons()    {        return $this->hasMany(Season::class);    }    public function watchedByUsers()    {        return $this->belongsToMany(User::class, 'movie_user_watched');    }    public function getCoverUrlAttribute()    {        // 1. Try parent's cover if exists        if ($this->cover_id) {            // Direct URL            if (str_starts_with($this->cover_id, 'http')) {                return $this->cover_id;            }            // TMDb Path            if (str_starts_with($this->cover_id, '/')) {                return 'https://image.tmdb.org/t/p/w500' . $this->cover_id;            }            // Local file (v2 local TMDb download or explicit path)            if (str_contains($this->cover_id, '.')) {                if (\Illuminate\Support\Facades\Storage::disk('public')->exists($this->cover_id)) {                    return \Illuminate\Support\Facades\Storage::disk('public')->url($this->cover_id);                }            }            // Legacy local cover format (v1.5)            $path = 'covers/' . $this->cover_id . 'f.jpg';            if (\Illuminate\Support\Facades\Storage::disk('public')->exists($path)) {                return \Illuminate\Support\Facades\Storage::disk('public')->url($path);            }        }        // 2. Fallback for boxsets: use the first child's cover        if ($this->boxsetChildren->count() > 0) {            $firstChild = $this->boxsetChildren->first();            if ($firstChild) {                return $firstChild->cover_url;            }        }        return null;    }    public function getBackdropUrlAttribute()    {        // 1. Specific backdrop_id        if ($this->backdrop_id) {            // Direct URL            if (str_starts_with($this->backdrop_id, 'http')) {                return $this->backdrop_id;            }            // TMDb Path            if (str_starts_with($this->backdrop_id, '/')) {                return 'https://image.tmdb.org/t/p/w1280' . $this->backdrop_id;            }            // Local file (v2 local TMDb download or explicit path)            if (str_contains($this->backdrop_id, '.')) {                if (\Illuminate\Support\Facades\Storage::disk('public')->exists($this->backdrop_id)) {                    return \Illuminate\Support\Facades\Storage::disk('public')->url($this->backdrop_id);                }            }            // Legacy local backdrop format            $path = 'backdrops/' . $this->backdrop_id . '.jpg';            if (\Illuminate\Support\Facades\Storage::disk('public')->exists($path)) {                return \Illuminate\Support\Facades\Storage::disk('public')->url($path);            }        }        // 2. Fallback for v1.5 movies: check 'b' version of the cover        if ($this->cover_id && !str_contains($this->cover_id, '/') && !str_starts_with($this->cover_id, 'http') && !str_contains($this->cover_id, '.')) {            $path = 'covers/' . $this->cover_id . 'b.jpg';            if (\Illuminate\Support\Facades\Storage::disk('public')->exists($path)) {                return \Illuminate\Support\Facades\Storage::disk('public')->url($path);            }        }        // 3. Fallback for boxsets: use the first child's backdrop/cover        if ($this->boxsetChildren->count() > 0) {            $firstChild = $this->boxsetChildren->first();            if ($firstChild) {                return $firstChild->backdrop_url;            }        }        return null;    }}